using System;
using System.Collections.Generic;
using System.Xml;

public class XmlConfigParser
{
    public static Dictionary<string, string> ParseXmlConfig(string xmlContent)
    {
        Dictionary<string, string> settings = new Dictionary<string, string>();
        XmlDocument xmlDoc = new XmlDocument();
        
        // Enable DTD processing for validation
        var settingsProperty = typeof(XmlDocument).GetProperty("Settings", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
        if (settingsProperty != null)
        {
            XmlReaderSettings readerSettings = (XmlReaderSettings)settingsProperty.GetValue(xmlDoc, null);
            readerSettings.DtdProcessing = DtdProcessing.Parse;
        }

        try
        {
            using (StringReader reader = new StringReader(xmlContent))
            {
                xmlDoc.Load(reader);
                XmlNodeList nodeList = xmlDoc.DocumentElement.ChildNodes;
                
                foreach (XmlNode node in nodeList)
                {
                    if (node.NodeType == XmlNodeType.Element && node.HasChildNodes)
                    {
                        string key = node.Name;
                        string value = node.InnerText.Trim();
                        settings[key] = value;
                    }
                }
            }
        }
        catch (XmlException ex)
        {
            throw new Exception("Error parsing XML: " + ex.Message);
        }

        return settings;
    }
}